package com.socialblog.notification.api;import com.socialblog.notification.application.NotificationService;import com.socialblog.notification.application.NotificationService.*;import org.springframework.data.domain.*;import org.springframework.security.core.annotation.AuthenticationPrincipal;import org.springframework.security.oauth2.jwt.Jwt;import org.springframework.web.bind.annotation.*;import java.util.UUID;@RestController @RequestMapping("/api/v1/notifications")public class NotificationController{private final NotificationService service;public NotificationController(NotificationService s){service=s;}@GetMapping Page<Response>list(@AuthenticationPrincipal Jwt j,@RequestParam(defaultValue="0")int page,@RequestParam(defaultValue="20")int size){return service.list(user(j),PageRequests.of(page,size,100));}@GetMapping("/unread-count")UnreadCount unread(@AuthenticationPrincipal Jwt j){return service.unread(user(j));}@PatchMapping("/{id}/read")Response read(@PathVariable UUID id,@AuthenticationPrincipal Jwt j){return service.read(id,user(j));}@PatchMapping("/read-all")UnreadCount readAll(@AuthenticationPrincipal Jwt j){return service.readAll(user(j));}private UUID user(Jwt j){return UUID.fromString(j.getSubject());}}
